            { group: 'Design & Formatting', items: ['Massive library of heavily styled, pre-formatted templates', 'One-click global aesthetic switching (Fonts, Colors)', 'ATS-friendly output formats (Machine-readable PDFs)', 'Personal portfolio mini-website generator'] }
